// ── Extract lead data from HubSpot contact ──────
const props = $input.first().json.properties || {};

// Extract domain from email or company website
let domain = '';
if (props.website) {
  domain = props.website.replace(/^(https?:\/\/)?(www\.)?/, '').replace(/\/.*$/, '');
} else if (props.email) {
  const emailDomain = props.email.split('@')[1] || '';
  const freeEmails = ['gmail.com', 'yahoo.com', 'hotmail.com', 'outlook.com', 'aol.com', 'icloud.com'];
  if (!freeEmails.includes(emailDomain)) {
    domain = emailDomain;
  }
}

const leadData = {
  email: props.email || null,
  first_name: props.firstname || null,
  last_name: props.lastname || null,
  company_name: props.company || null,
  company_domain: domain || null,
  job_title: props.jobtitle || null,
  phone: props.phone || null,
  source: props.hs_lead_source || 'hubspot',
  message: null,
  _hubspot_contact_id: $input.first().json.id,
};

return [{ json: leadData }];

// ── Build HubSpot update + Slack payloads ────────
const leads = $input.first().json.leads || [];
const lead = leads[0] || {};
const score = (lead.scores && lead.scores[0]) || {};
const hubspotContactId = $('Extract Lead Data').first().json._hubspot_contact_id;

const contactName = lead.contact_full_name || [lead.first_name, lead.last_name].filter(Boolean).join(' ') || 'Unknown';
const companyName = lead.company_legal_name || lead.company_name || lead.company_domain || 'Unknown';
const title = lead.contact_title || lead.job_title || 'Unknown';
const industry = lead.company_industry || 'Unknown';
const composite = score.composite_score || 0;
const temperature = score.temperature || 'cold';
const decision = score.decision || 'needs_review';
const reasoning = score.decision_reasoning || '';

// AI data
const icpFit = Math.round((lead.ai_icp_fit_score || 0) * 100);
const urgency = lead.ai_urgency || 'exploratory';
const summary = lead.ai_company_summary || '';
const signals = (lead.ai_buying_signals || []).map(s => typeof s === 'string' ? s : s.signal).filter(Boolean);
const pains = (lead.ai_pain_points || []).map(p => typeof p === 'string' ? p : p.pain_point).filter(Boolean);
const talkingPts = lead.ai_talking_points || [];
const confidence = Math.round((lead.overall_confidence || 0) * 100);

// Lifecycle stage mapping
const lifecycleMap = {
  qualified: 'salesqualifiedlead',
  nurture: 'marketingqualifiedlead',
  needs_review: 'lead',
  disqualified: 'other',
};

return [{
  json: {
    hubspotContactId,
    contactName, companyName, title, industry,
    composite, temperature, decision, reasoning,
    icpFit, urgency, summary,
    signals, signalsText: signals.join('; '),
    pains, painsText: pains.join('; '),
    talkingPts, talkingPtsText: talkingPts.join('; '),
    confidence,
    firmographic: score.firmographic_score || 0,
    demographic: score.demographic_score || 0,
    behavioral: score.behavioral_score || 0,
    aiFit: score.ai_fit_score || 0,
    lifecycleStage: lifecycleMap[decision] || 'lead',
    email: lead.email || '',
    employees: lead.company_employee_count,
    revenue: lead.company_revenue,
    domain: lead.company_domain || '',
  }
}];

